import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "../api/axios";

export default function ReceiptPage() {
    const { bookingId } = useParams();
    const navigate = useNavigate();
    const [booking, setBooking] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchBooking = async () => {
            try {
                // Determine API endpoint based on role? 
                // Regular users can use /bookings/my but it returns an array.
                // Admin can use /admin/bookings.
                // We might need a specific endpoint for a single booking or filter from "myBookings".
                // For now, let's try to filter from myBookings or add a getBookingById endpoint.
                // Actually, let's add specific endpoint logic or just filter for now to be safe.
                const res = await axios.get("/bookings/my");
                const found = res.data.find(b => b._id === bookingId);

                if (found) {
                    setBooking(found);
                } else {
                    // Fallback or error
                    console.error("Booking not found in user history");
                }
                setLoading(false);
            } catch (err) {
                console.error("Error fetching receipt", err);
                setLoading(false);
            }
        };
        fetchBooking();
    }, [bookingId]);

    if (loading) return <div style={{ textAlign: "center", marginTop: "50px" }}>Loading Receipt...</div>;
    if (!booking) return <div style={{ textAlign: "center", marginTop: "50px" }}>Receipt Not Found</div>;

    // QR Data: URL for Verification
    const verificationUrl = `${window.location.origin}/verify/${bookingId}`;

    // Using a public API for QR Code generation to avoid dependencies
    const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(verificationUrl)}`;

    return (
        <div className="auth-container" style={{ padding: "40px 20px" }}>
            <div style={{ background: "var(--bg-secondary)", borderRadius: "20px", border: "1px solid rgba(255,255,255,0.05)", boxShadow: "var(--shadow-neon-cyan)", maxWidth: "450px", width: "100%", overflow: "hidden", position: "relative" }}>
                
                {/* Header */}
                <div style={{ background: "rgba(0, 240, 255, 0.1)", borderBottom: "1px solid var(--accent-cyan)", padding: "25px", textAlign: "center", color: "white" }}>
                    <h2 style={{ margin: 0, fontSize: "1.8rem", color: "var(--accent-cyan)", textShadow: "var(--shadow-neon-cyan)", letterSpacing: "2px" }}>DIGITAL PASS</h2>
                    <p style={{ margin: "5px 0 0", color: "var(--text-secondary)", fontSize: "0.9rem", letterSpacing: "1px" }}>AUTHORIZED ACCESS TOKEN</p>
                </div>

                {/* Content */}
                <div style={{ padding: "35px", textAlign: "center", position: "relative" }}>
                    {/* Glowing BG for QR */}
                    <div style={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%, -50%)", width: "220px", height: "220px", background: "var(--accent-cyan)", filter: "blur(50px)", opacity: "0.2", zIndex: 0 }}></div>
                    
                    <img src={qrUrl} alt="Booking QR" style={{ borderRadius: "15px", border: "3px solid var(--accent-cyan)", position: "relative", zIndex: 1, padding: "10px", background: "white" }} />
                    <p style={{ marginTop: "20px", color: "var(--accent-cyan)", fontSize: "0.9rem", letterSpacing: "1px", fontWeight: "bold" }}>[ SCAN AT GATEWAY ]</p>

                    <div style={{ textAlign: "left", marginTop: "35px", borderTop: "1px dashed rgba(255,255,255,0.1)", paddingTop: "25px", position: "relative", zIndex: 1 }}>
                        <DetailRow label="VEHICLE ID" value={booking.vehicleNumber} />
                        <DetailRow label="SECTOR" value={booking.slotId?.parkingLotId?.name || "ParkSense Lot"} />
                        <DetailRow label="BAY" value={`#${booking.slotId?.slotNumber}`} />
                        <DetailRow label="SYSTEM IN" value={new Date(booking.startTime).toLocaleString()} />
                        <DetailRow label="SYSTEM OUT" value={new Date(booking.endTime).toLocaleString()} />
                        <DetailRow label="CREDITS EXCHANGED" value={`$${booking.amount || 10}`} bold />
                    </div>
                </div>

                {/* Footer */}
                <div style={{ background: "rgba(255,255,255,0.02)", borderTop: "1px solid rgba(255,255,255,0.05)", padding: "20px", display: "flex", gap: "10px", justifyContent: "center" }}>
                    <button
                        onClick={() => window.print()}
                        className="btn-primary"
                        style={{ flex: 1, padding: "12px", background: "transparent", border: "1px solid var(--accent-cyan)", color: "var(--accent-cyan)", boxShadow: "none" }}
                    >
                        EXPORT
                    </button>
                    <button
                        onClick={() => navigate("/")}
                        className="btn-primary"
                        style={{ flex: 1, padding: "12px" }}
                    >
                        HOME
                    </button>
                </div>
            </div>
        </div>
    );
}

const DetailRow = ({ label, value, bold }) => (
    <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "15px", fontSize: "0.9rem", letterSpacing: "1px" }}>
        <span style={{ color: "var(--text-secondary)" }}>{label}</span>
        <span style={{ color: bold ? "var(--accent-green)" : "var(--text-primary)", fontWeight: bold ? "bold" : "normal", textShadow: bold ? "var(--shadow-neon-green)" : "none" }}>{value}</span>
    </div>
);
